    protected function normalizePath(string $url): string
    {
        $parts = parse_url($url);
        if (!$parts) {
            return $url;
        }

        $scheme = $parts['scheme'] ?? 'https';
        $host = $parts['host'] ?? '';
        $port = isset($parts['port']) ? ':' . $parts['port'] : '';
        $path = $parts['path'] ?? '/';
        $query = isset($parts['query']) ? '?' . $parts['query'] : '';
        $fragment = isset($parts['fragment']) ? '#' . $parts['fragment'] : '';

        $segments = explode('/', $path);
        $resolved = [];

        foreach ($segments as $seg) {
            if ($seg === '' || $seg === '.') {
                continue;
            }
            if ($seg === '..') {
                array_pop($resolved);
                continue;
            }
            $resolved[] = $seg;
        }

        $normPath = '/' . implode('/', $resolved);

        return $scheme . '://' . $host . $port . $normPath . $query . $fragment;
    }

    protected function stripInvalidUtf8(string $html): string
